        let stDt = ed_stDt.getValue();
    	let edDt = ed_edDt.getValue();
        let msgSearch = "기간 - " + stDt.substring(0,4) + "/" + stDt.substring(4,6) + "/" + stDt.substring(6,8)
					  + " ~ " + edDt.substring(0,4) + "/" + edDt.substring(4,6) + "/" + edDt.substring(6,8);

        const options = {
            fileName : "업무용차량비용관리.xlsx", 
            sheetName : "업무용차량비용관리",
            startRowIndex : 4,
            startColumnIndex : 0
        };

        const infoArr = [
            {
            rowIndex : 0, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 17, 
            text : "업무용차량비용관리" , 
            textAlign : "center",
            fontSize : 24
            },
            {
            rowIndex : 1, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 17
            },
            {
            rowIndex : 2, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 17, 
            text : msgSearch , 
            textAlign : "left",
            fontSize : 12
            },
            {
            rowIndex : 3, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 17
            }      

        ];
        $c.data.downloadGridViewExcel(gr_bizcarResults, options, infoArr);
    }

};

